UPDATE public.training_items ti
SET body = $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Säljprocessen i överblick"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör allt"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "En säljare som kan processen tappar aldrig fotfästet – du vet alltid var i affären du är och vad nästa steg är. De flesta förlorade affärer beror inte på fel produkt eller pris, utan på att säljaren hoppade över ett steg (oftast behovsanalysen) och presenterade för tidigt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "De sju stegen och varför ordningen är helig"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Var affären vinns respektive förloras"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hur du alltid vet ditt nästa steg"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "De sju stegen"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Prospektering – "}, {"type": "text", "text": "du hittar och kvalificerar rätt företag."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Första kontakt – "}, {"type": "text", "text": "du tar dig in med en konkret krok, oftast via ett kort samtal."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Behovsanalys – "}, {"type": "text", "text": "du gräver fram det verkliga behovet. Här vinns affären."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Förslag och offert – "}, {"type": "text", "text": "du presenterar bara det som löser behovet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Invändningshantering – "}, {"type": "text", "text": "du bekräftar, vänder till värde och ställer en fråga."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Avslut – "}, {"type": "text", "text": "du får till ett avtal, lugnt och utan press."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Överlämning – "}, {"type": "text", "text": "bygg-teamet tar över och kontaktar kunden."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att presentera lösning innan du förstått behovet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att se överlämningen som 'klart' – där befästs förtroendet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att alltid avsluta en kontakt med ett bokat nästa steg."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Rita de sju stegen ur minnet och skriv en mening om ditt mål i varje steg."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: målet i steg 1–2 är ett möte, i steg 3 att förstå behovet, i steg 4–6 ett avtal, i steg 7 en trygg överlämning."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Prospektering: hitta rätt företag"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Säljer du till fel företag spelar ingen teknik någon roll. Bra prospektering betyder att du lägger tiden på företag som både har ett behov och kan fatta beslut. Tio rätt företag slår hundra slumpvisa."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Vilka köpsignaler du ska leta efter"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hur du kvalificerar innan du ringer"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hur du formulerar en konkret krok"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Köpsignaler att leta efter"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Daterad sajt: "}, {"type": "text", "text": "gammal, långsam eller inte mobilanpassad."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Svag synlighet: "}, {"type": "text", "text": "rankar inte på sina egna tjänster på Google."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Tillväxt: "}, {"type": "text", "text": "anställer, expanderar, syns i lokala nyheter."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Lucka: "}, {"type": "text", "text": "säljer produkter men saknar e-handel."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så kvalificerar du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Behov – "}, {"type": "text", "text": "finns en tydlig lucka du kan lösa?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Storlek – "}, {"type": "text", "text": "har de råd och volym nog för en bra affär?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Beslutsfattare – "}, {"type": "text", "text": "når du någon som kan säga ja?"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel på en krok"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "\"Jag såg att ni inte syns på sökningen 'takläggare Göteborg' – det är förmodligen kunder som hamnar hos en konkurrent. Det var därför jag hörde av mig.\""}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att ringa utan en konkret observation – generiska samtal avfärdas direkt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att jaga kvantitet utan kvalificering."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att alltid anteckna din observation innan du ringer."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Hitta tre företag idag. Skriv för varje en köpsignal och en mening du skulle öppna med."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: en bra öppning namnger en konkret iakttagelse om just dem och slutar med en fråga."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Behovsanalys och pitch som landar"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Behovsanalysen är där affären vinns. När du förstår kundens verkliga smärta kan din pitch bli en spegel av deras egna ord, och då känns lösningen självklar. Pitchar du utan att ha grävt blir det en gissning – och gissningar bemöts med 'det är för dyrt'."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Lyssna mer än du pratar (sikta på 70 procent)"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Koppla pitchen till kundens exakta ord"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Föreslå en sak, inte hela katalogen"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gräv – "}, {"type": "text", "text": "ställ öppna frågor och låt kunden beskriva problemet och vad det kostar."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Bekräfta – "}, {"type": "text", "text": "sammanfatta: 'Så om jag förstår dig rätt…' och få ett 'ja, precis'."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Spegla – "}, {"type": "text", "text": "presentera lösningen med kundens egna nyckelord."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Avgränsa – "}, {"type": "text", "text": "föreslå det som löser deras största problem, inget mer."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Du: "}, {"type": "text", "text": "Du sa att nästan ingen hör av sig via sajten och att ni tappar jobb till konkurrenten."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Du: "}, {"type": "text", "text": "Då föreslår jag en ny företagshemsida med SEO, så att de som söker er faktiskt hittar er och hör av sig."}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att rabbla funktioner – kunden köper resultat, inte funktioner."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att presentera flera paket på en gång."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att låta tystnaden jobba efter en bra fråga."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Skriv fem öppna frågor du kan ställa i nästa behovsanalys."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: bra frågor börjar med Hur, Vad eller Varför och handlar om kundens mål, nuläge och vad problemet kostar."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Avslut och överlämning"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Säljarens jobb slutar vid avtalet, inte vid ett påtvingat ja. Ett lugnt avslut bygger förtroende; ett pressat avslut skapar ånger. När avtalet är på plats tar bygg-teamet över och kontaktar kunden, precis som ni kommit överens om."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Avsluta utan press – målet är ett avtal"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Föreslå nästa steg konkret"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Lämna över så kunden känner sig trygg"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sammanfatta värdet – "}, {"type": "text", "text": "knyt ihop med det kunden själv sagt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Föreslå lugnt – "}, {"type": "text", "text": "'Känns det här rätt? Då sätter vi det på pränt i ett enkelt avtal.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Lämna över – "}, {"type": "text", "text": "'Sen tar vårt team vid och hör av sig för att dra igång.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Boka tiden – "}, {"type": "text", "text": "bekräfta nästa steg direkt innan ni avslutar."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "\"Du sa att ni tappar jobb till konkurrenten – det här vänder det. Känns det rätt sätter vi det på pränt, så tar vårt team över och hör av sig nästa vecka. Låter det som en bra plan?\""}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "hårda avslutstekniker – är värdet tydligt säljer det sig självt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att lämna mötet utan ett bokat nästa steg."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att vara konkret om vad som händer efter avtalet."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Skriv en avslutsmening som föreslår ett avtal utan att kännas påträngande."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: en bra avslutsmening sammanfattar värdet, föreslår avtalet och slutar med en lätt fråga att säga ja till."}]}]}$j$::jsonb
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Grundkurs: Sälj från A till Ö';

UPDATE public.training_items ti
SET body = $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Öppna och slutna frågor"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Frågorna du ställer styr hela samtalet. Slutna frågor ger ja eller nej och stänger dörren; öppna frågor får kunden att prata, och då lär du dig vad du behöver för att sälja. En säljare som behärskar frågetekniken behöver knappt pitcha – kunden gör jobbet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Skillnaden mellan öppna och slutna frågor"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "När du ska använda vilken"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tumregeln 80/20 i behovsanalysen"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öppna brett – "}, {"type": "text", "text": "börja med Hur, Vad eller Varför: 'Hur får ni in nya kunder idag?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Håll 80/20 – "}, {"type": "text", "text": "cirka 80 procent öppna frågor i analysen; slutna sparar du till slutet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Stäng med slutna – "}, {"type": "text", "text": "när du ska bekräfta och boka: 'Passar tisdag 10?'"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Stängt: "}, {"type": "text", "text": "'Är ni nöjda med er hemsida?' (ger bara ja/nej)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öppet: "}, {"type": "text", "text": "'Vad skulle ni vilja att hemsidan gjorde för er?' (får kunden att prata)"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att ställa ledande slutna frågor tidigt – samtalet dör."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att kedja flera frågor på rad utan att lyssna på svaret."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att följa upp varje svar med en ny öppen fråga."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Skriv om tre slutna frågor du brukar ställa till öppna."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: byt 'Har ni…' mot 'Hur/Vad…' och låt frågan handla om kundens situation, inte om ett ja."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Hitta den verkliga smärtan"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ingen betalar för en hemsida. De betalar för att lösa en smärta: för få kunder, ser oseriösa ut, tappar jobb till konkurrenten. Din uppgift är att gräva tills smärtan blir konkret och kännbar – för kunden, inte bara för dig."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Skilja ytbehov ('en ny sajt') från verkligt behov ('fler kunder')"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Använda frågetrappan för att göra smärtan dyr"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Få kunden att själv sätta ord på värdet"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Frågetrappan steg för steg"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Situationsfråga – "}, {"type": "text", "text": "kartlägg nuläget kort: 'Hur får ni in nya kunder idag?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Problemfråga – "}, {"type": "text", "text": "hitta vad som skaver: 'Vad är svårast med att få in förfrågningar?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Konsekvensfråga – "}, {"type": "text", "text": "gör problemet dyrt: 'Vad innebär det för omsättningen att ni tappar dem?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Nyttofråga – "}, {"type": "text", "text": "låt kunden beskriva värdet: 'Om ni fick dubbelt så många – vad vore det värt?'"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Du: "}, {"type": "text", "text": "Vad är svårast med att få in nya förfrågningar?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Kund: "}, {"type": "text", "text": "Ärligt talat hör nästan ingen av sig via sajten."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Du: "}, {"type": "text", "text": "Tappar ni då affärer till konkurrenter som syns bättre?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Kund: "}, {"type": "text", "text": "Antagligen. Vi vet att de ligger högre på Google."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Du: "}, {"type": "text", "text": "Om sajten drog in fem förfrågningar i månaden – vad vore det värt?"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Kund: "}, {"type": "text", "text": "Det skulle förändra hela vårt år."}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att hoppa från situation rakt till pitch."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att ställa konsekvensfrågor som ett förhör – håll det varmt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att anteckna kundens exakta ord till pitchen."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Skriv en frågetrappa (en fråga per steg) för en lokal redovisningsbyrå med en gammal sajt."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: situation → problem → konsekvens (vad det kostar) → nytta (vad en lösning vore värd)."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Aktivt lyssnande"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kunden köper av den som förstår dem. Aktivt lyssnande gör att kunden känner sig hörd och avslöjar mer – och ger dig de nyckelord du återanvänder i pitchen. Den som pratar minst lär sig mest."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Prata mindre, pausa mer"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Spegla och bekräfta"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Fånga nyckelord du kan använda senare"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pausa – "}, {"type": "text", "text": "var tyst efter en fråga och låt kunden fylla i."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Spegla – "}, {"type": "text", "text": "upprepa med egna ord: 'Så det viktigaste är…'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Följ upp – "}, {"type": "text", "text": "ställ följdfrågor på det kunden faktiskt sa, inte på din agenda."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Anteckna – "}, {"type": "text", "text": "skriv ner exakta uttryck kunden använder."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att planera din nästa fråga medan kunden pratar."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att fylla varje tystnad."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att sammanfatta innan du går vidare."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "I nästa möte: håll dig till att lyssna omkring 70 procent av tiden och notera tre nyckelord kunden använder."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: nyckelord är de ord kunden själv väljer för sitt problem och mål – använd dem ordagrant i pitchen."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Sammanfatta och koppla behov till lösning"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Bron mellan analys och pitch är en sammanfattning som kunden bekräftar. Ett 'ja, precis' innan du föreslår något gör att lösningen landar som ett svar på deras behov – inte som en säljares gissning."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Sammanfatta behovet och få ett ja"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Översätta behovet till rätt paket"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Föreslå en sak som löser största problemet"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sammanfatta – "}, {"type": "text", "text": "'Om jag förstått rätt är X viktigast och Y skaver mest – stämmer det?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Matcha – "}, {"type": "text", "text": "koppla behovet till en lösning: behov av fler kunder → hemsida + SEO."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Avgränsa – "}, {"type": "text", "text": "föreslå det som löser deras största problem, inte hela katalogen."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Knyt ihop – "}, {"type": "text", "text": "säg det med kundens egna ord."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "\"Du sa att tid är er flaskhals och att ni tappar förfrågningar. Då föreslår jag en sajt som fångar förfrågningarna åt er automatiskt – så slipper ni det manuella.\""}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att pitcha innan kunden bekräftat behovet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att föreslå allt på en gång."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att para ihop ett behov med exakt en lösning."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Para ihop tre vanliga behov med rätt paket och motivera kort varför."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: fler kunder → hemsida + SEO; intern process som skaver → webbapp; finnas i fickan → mobilapp."}]}]}$j$::jsonb
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Behovsanalys & frågeteknik';

UPDATE public.training_items ti
SET body = $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Metoden: bekräfta, vänd, fråga"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "En invändning är inte ett nej – det är en begäran om mer trygghet. Säljare som blir defensiva förlorar; de som bekräftar, vänder till värde och ställer en fråga behåller både relationen och affären. Rätt mindset: invändningen är en inbjudan, inte en attack."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tresstegsmetoden för varje invändning"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Rätt mindset så du aldrig blir defensiv"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hur en fråga för samtalet framåt"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Metoden steg för steg"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Bekräfta – "}, {"type": "text", "text": "möt känslan så kunden känns hörd: 'Jag förstår, det är en investering.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vänd – "}, {"type": "text", "text": "byt vinkel till värde: 'Men en extra kund i månaden betalar den.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Fråga – "}, {"type": "text", "text": "för samtalet framåt: 'Vad är en ny kund värd för er?'"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "\"Jag förstår att det känns som mycket (bekräfta). Samtidigt: drar sajten in en enda extra kund i månaden har den betalat sig (vänd). Vad är en ny kund värd för er? (fråga)\""}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att gå i försvar eller argumentera emot."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att sänka priset direkt vid första motståndet."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att alltid avsluta med en fråga."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Använd metoden på invändningen 'vi har redan en hemsida'."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: bekräfta att det är bra, vänd till om den presterar, fråga 'hur många leads drar den in i månaden?'."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – \"Det är för dyrt\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Den vanligaste invändningen betyder nästan aldrig 'vi saknar pengar' – den betyder 'jag ser inte värdet än'. Hanterar du den genom att sänka priset lär du kunden att pruta. Hanterar du den genom att höja värdet vinner du affären till rätt pris."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tolka vad 'för dyrt' egentligen betyder"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Vända priset till avkastning"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Erbjuda en mindre nivå istället för rabatt"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Bekräfta – "}, {"type": "text", "text": "'Jag förstår, det är en investering.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vänd till ROI – "}, {"type": "text", "text": "räkna i kunder: 'Vad är en ny kund värd? En extra i månaden och den är betald.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Erbjud en väg in – "}, {"type": "text", "text": "'Vi kan börja i en mindre nivå och bygga vidare när det ger resultat.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Fråga – "}, {"type": "text", "text": "'Vad skulle få det här att kännas som en självklar investering?'"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att sänka priset reflexmässigt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att försvara priset med funktioner."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att alltid prata om vad det ger, inte vad det kostar."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Skriv ditt eget svar på 'det är för dyrt' i tre meningar (bekräfta, vänd, fråga)."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: en stark replik erkänner investeringen, översätter priset till avkastning och slutar med en fråga."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Snabbguide till de vanligaste invändningarna"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kan du svaren i sömnen tappar du aldrig tempo. Nästan alla invändningar är varianter på samma åtta – lär dig grundsvaret på var och en så blir du aldrig ställd."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "De åtta och din vinkel"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vi har redan en hemsida: "}, {"type": "text", "text": "'Vad bra – hur många leads drar den in i månaden?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vi gör det själva: "}, {"type": "text", "text": "'Är det där ni tjänar mest pengar? Varje timme på sajten är bort från kärnverksamheten.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vi har ingen tid: "}, {"type": "text", "text": "'Just därför – vi sköter nästan allt åt er.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Skicka info: "}, {"type": "text", "text": "'Gärna – vad är viktigast för er, så skickar jag rätt sak och stämmer av på fredag.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Nöjda med nuvarande leverantör: "}, {"type": "text", "text": "'Vad bra. Många använder oss som komplement för t.ex. SEO eller GEO.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Funkar SEO/GEO?: "}, {"type": "text", "text": "'Bra att vara kritisk – vi mäter allt, ni ser ranking och leads varje månad.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Måste tänka på det: "}, {"type": "text", "text": "'Klokt. Är det priset, tajmingen eller något annat ni vill fundera på?'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det är för dyrt: "}, {"type": "text", "text": "'Det är en investering – vad är en ny kund värd för er?'"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att attackera nuvarande leverantör."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att ta invändningen personligt."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att bekräfta först, alltid."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Be en kollega skjuta de åtta invändningarna mot dig och svara direkt enligt bekräfta–vänd–fråga."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: alla åtta löses med samma struktur – bara vinkeln i 'vänd' ändras."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Förhandla på värde, inte pris"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Varför det här avgör affären"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Priset är det sista du rör. Förhandlar du genom att sänka priset urholkar du både marginal och ditt värde i kundens ögon. Förhandlar du genom att justera omfång och be om något tillbaka behåller du värdet och får en bättre affär."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Ankra med ditt ordinarie pris"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Sänk omfång före pris"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Ge aldrig utan att få något tillbaka"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Så gör du"}]}, {"type": "orderedList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ankra – "}, {"type": "text", "text": "presentera ditt fulla pris och värde först."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Justera omfång – "}, {"type": "text", "text": "'Vi kan börja i en mindre nivå' i stället för att rabattera."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Byt, ge inte bort – "}, {"type": "text", "text": "'Jag kan lösa det priset om vi skriver ett längre avtal eller ni blir referens.'"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Håll tystnad – "}, {"type": "text", "text": "efter ett bud – den som pratar först förlorar ofta."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ordagrant exempel"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "\"Jag kan möta er på priset om vi tar ett tolvmånadersavtal i stället för månadsvis – då vet vi båda att vi bygger något långsiktigt. Funkar det för er?\""}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vanliga misstag"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att ge rabatt utan motprestation."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Undvik: "}, {"type": "text", "text": "att förhandla mot dig själv genom att fylla tystnaden."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Gör: "}, {"type": "text", "text": "att alltid påminna om resultatet, inte kostnaden."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Lista tre saker du kan be om i utbyte mot en prisjustering."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Facit: längre avtal, snabbare beslut, referens/case, fler tjänster i paketet eller förskottsbetalning."}]}]}$j$::jsonb
